from __future__ import division
import numpy as np
cimport numpy as np
from libc.math cimport exp

#Use cython to calculate R matrix

def getR11(long N,double beta1,np.ndarray[np.float64_t, ndim=2] pos):
    cdef np.ndarray[np.float64_t, ndim = 2] R11 = np.zeros((N,1),dtype = np.float64)
    cdef int i
    for i in range(1,N):
        R11[i,0] = (1+R11[i-1,0])*exp(-beta1*(pos[i,0]-pos[i-1,0]))
    return R11

def getR12(long N, long M, double beta1, np.ndarray[np.float64_t, ndim =2] pos, np.ndarray[np.float64_t, ndim = 2] neg):
    cdef np.ndarray[np.float64_t, ndim =2] R12 = np.zeros((N,1),dtype = np.float64)
    cdef int i,j
    cdef double tempsum = 0.0
    for i in range(1,N):
        tempsum = 0.0
        for j in range(M):
            if neg[j,0] >= pos[i,0]:
                break
            if neg[j,0] >= pos[i-1,0] and neg[j,0] < pos[i,0]:
                tempsum += exp(-beta1*(pos[i,0] - neg[j,0]))
        R12[i,0] = R12[i-1,0]*exp(-beta1*(pos[i,0]-pos[i-1,0])) + tempsum
    return R12

def getR21(long N,long M, double beta2, np.ndarray[np.float64_t, ndim = 2] pos,np.ndarray[np.float64_t, ndim = 2] neg):
    cdef np.ndarray[np.float64_t, ndim = 2] R21 = np.zeros((M,1),dtype = np.float64)
    cdef int i,j
    cdef double tempsum = 0.0
    for j in range(1,M):
        tempsum=0.0
        for i in range(N):
            if pos[i,0] > neg[j,0]:
                break
            if pos[i,0] >= neg[j-1,0] and pos[i,0] < neg[j,0]:
                tempsum += np.exp(-beta2*(neg[j,0]-pos[i,0]))
        R21[j,0] = R21[j-1,0]*np.exp(-beta2*(neg[j,0]-neg[j-1,0])) + tempsum
    return R21

def getR22(long M, double beta2,np.ndarray[np.float64_t, ndim =2] neg):
    cdef np.ndarray[np.float64_t, ndim = 2] R22 = np.zeros((M,1),dtype = np.float64)
    cdef int j
    for j in range(1,M):
        R22[j,0] = (1+R22[j-1,0])*np.exp(-beta2*(neg[j,0]-neg[j-1,0]))
    return R22

import binascii
import datetime
import os
import struct
import time

from cpython.version cimport PY_MAJOR_VERSION

from cyksuid.fast_base62 cimport fast_b62decode
from cyksuid.fast_base62 cimport fast_b62encode

DEF _BYTE_LENGTH = 20
DEF _STRING_ENCODED_LENGTH = 27
DEF _TIMESTAMP_LENGTH = 4
DEF _BODY_LENGTH = 16
DEF _EPOCH_STAMP = 1400000000

BYTE_LENGTH = _BYTE_LENGTH
STRING_ENCODED_LENGTH = _STRING_ENCODED_LENGTH
# A bytes-encoded maximum value for a KSUID
MAX_ENCODED = b"aWgEPTl1tmebfsQzFP4bxwgy80V"


cdef class KSUID(object):
    def __init__(self, bytes s):
        if not s:
            s = b'\x00' * _BYTE_LENGTH
        if len(s) != _BYTE_LENGTH:
            raise TypeError("not a valid ksuid bytes")
        self._bytes = s
        # Remove padding
        self._data = s.lstrip(b'\x00')

    property datetime:
        """Timestamp portion of the ID as a datetime.datetime object."""
        def __get__(self):

            ts = self.timestamp
            return datetime.datetime.utcfromtimestamp(ts + _EPOCH_STAMP)

    property timestamp:
        """Timestamp portion of the ID in seconds."""
        def __get__(self):
            return struct.unpack('>i', self._bytes[:_TIMESTAMP_LENGTH])[0]

    property payload:
        """Payload portion of the ID."""
        def __get__(self):
            return self._bytes[:_BODY_LENGTH]

    property bytes:
        """Raw bytes representation of the ID."""
        def __get__(self):
            return self._bytes

    property hex:
        """Hex encoded representation of the ID."""
        def __get__(self):
            return binascii.b2a_hex(self._bytes)

    property encoded:
        """Base62 encoded representation of the ID."""
        def __get__(self):
            return fast_b62encode(self._bytes)

    def __hash__(self):
        return hash(self._data)

    def __repr__(self):
        return 'KSUID(%r)' % str(self)

    def __str__(self):
        s = fast_b62encode(self._bytes)
        if PY_MAJOR_VERSION >= 3:
            return s.decode('ascii')
        return s

    def __len__(self):
        return len(self._data)

    def __richcmp__(KSUID self, object other, int op):
        if not isinstance(other, KSUID):
            return NotImplemented

        cdef KSUID that = <KSUID>other
        if op == 0:  # <
            return self._bytes < that._bytes
        elif op == 2:  # ==
            return self._bytes == that._bytes
        elif op == 4:  # >
            return self._bytes > that._bytes
        elif op == 1:  # <=
            return self._bytes <= that._bytes
        elif op == 3:  # !=
            return self._bytes != that._bytes
        elif op == 5:  # >=
            return self._bytes >= other._bytes

    def __setattr__(self, name, value):
        raise TypeError('KSUID objects are immutable')

    def __delattr__(self, name):
        raise TypeError('KSUID objects are immutable')


cpdef KSUID from_bytes(bytes s):
    """Construct KSUID from raw bytes."""
    return KSUID(s)


cpdef KSUID from_parts(int timestamp, bytes payload):
    """Construct KSUID from timestamp."""
    timestamp -= _EPOCH_STAMP
    s = struct.pack('>i', timestamp) + payload
    return KSUID(s)


def ksuid(time_func=time.time, rand_func=os.urandom):
    """Factory to construct KSUID objects.

    :param callable time_func: function for generating time, defaults to time.time.
    :param callable rand_func: function for generating random bytes, defaults to os.urandom.
    """
    timestamp = int(time_func())
    payload = rand_func(_BODY_LENGTH)
    return from_parts(timestamp, payload)


cpdef KSUID parse(s):
    """Parse KSUID from a base62 encoded string."""
    if isinstance(s, unicode):
        s = (<unicode>s).encode('utf-8')
    if len(s) != _STRING_ENCODED_LENGTH:
        raise TypeError("invalid encoded KSUID string")

    return from_bytes(fast_b62decode(s))


